"use client";

import { useState } from "react";
import { motion } from "framer-motion";

const socials = [
  {
    label: "Email",
    value: "jai.dilbaghi@gmail.com",
    href: "mailto:jai.dilbaghi@gmail.com",
  },
  {
    label: "LinkedIn",
    value: "/in/jaidilbaghi",
    href: "https://linkedin.com/in/jaidilbaghi",
  },
  {
    label: "GitHub",
    value: "/jaidilbaghi",
    href: "https://github.com/jaidilbaghi",
  },
];

export default function Contact() {
  const [form, setForm] = useState({ name: "", email: "", message: "" });
  const [status, setStatus] = useState<"idle" | "sending" | "sent">("idle");

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    setForm((prev) => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus("sending");
    await new Promise((resolve) => setTimeout(resolve, 900));
    setStatus("sent");
    setForm({ name: "", email: "", message: "" });
  };

  return (
    <section className="pt-28 pb-16 md:pt-32 md:pb-20">
      <div className="page-shell">
        <div className="grid lg:grid-cols-[0.9fr_1.1fr] gap-8 items-start">
          <div>
            <h2 className="font-display text-4xl md:text-5xl leading-[0.95] max-w-xl">
              Contact
            </h2>
            <p className="mt-4 max-w-xl text-base leading-relaxed text-text-secondary">
              Email is the easiest way to reach me. I am open to internships, research, and
              project work.
            </p>

            <div className="mt-8 space-y-3">
              {socials.map(({ label, value, href }) => (
                <a
                  key={label}
                  href={href}
                  target={label !== "Email" ? "_blank" : undefined}
                  rel="noopener noreferrer"
                  className="group flex items-baseline gap-3 text-sm"
                >
                  <span className="w-20 text-text-muted">{label}</span>
                  <span className="text-text-primary group-hover:text-[var(--accent-1)]">{value}</span>
                </a>
              ))}
            </div>
          </div>

          <div>
            {status === "sent" ? (
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="py-12"
              >
                <p className="font-display text-3xl">Sent</p>
                <p className="mt-2 text-sm text-text-secondary">
                  I will get back to you soon.
                </p>
              </motion.div>
            ) : (
              <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                  <label className="mb-2 block text-[11px] font-mono uppercase tracking-[0.18em] text-text-muted">
                    Name
                  </label>
                  <input
                    name="name"
                    value={form.name}
                    onChange={handleChange}
                    className="input-field"
                    placeholder="Your name"
                    required
                  />
                </div>
                <div>
                  <label className="mb-2 block text-[11px] font-mono uppercase tracking-[0.18em] text-text-muted">
                    Email
                  </label>
                  <input
                    name="email"
                    type="email"
                    value={form.email}
                    onChange={handleChange}
                    className="input-field"
                    placeholder="you@example.com"
                    required
                  />
                </div>
                <div>
                  <label className="mb-2 block text-[11px] font-mono uppercase tracking-[0.18em] text-text-muted">
                    Message
                  </label>
                  <textarea
                    name="message"
                    rows={5}
                    value={form.message}
                    onChange={handleChange}
                    className="input-field resize-none"
                    placeholder="What are you building?"
                    required
                  />
                </div>
                <button
                  type="submit"
                  disabled={status === "sending"}
                  className="btn-primary disabled:opacity-70"
                >
                  {status === "sending" ? "Sending" : "Send"}
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
    </section>
  );
}
